spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 11000;
    var progress = (t % duration) / duration;

    // Coordinates for grid columns
    var colOnes = W / 2 - 35;
    var colDot = W / 2 - 12;
    var colTenths = W / 2 + 10;
    var colHund = W / 2 + 35;

    var rowCarry = H / 2 - 45;
    var rowVal1 = H / 2 - 25;
    var rowVal2 = H / 2 - 2;
    var rowLine = H / 2 + 16;
    var rowSum = H / 2 + 36;

    // Stages
    // 0 - 2s: Stage 1 (Setup numbers, highlight dots)
    // 2s - 4.2s: Stage 2 (Hundredths column: 5 + 0 = 5)
    // 4.2s - 6.5s: Stage 3 (Tenths column: 7 + 8 = 15. Write 5, carry 1)
    // 6.5s - 8.8s: Stage 4 (Ones column: 4 + 1 + 1 = 6)
    // 8.8s - 11s: Stage 5 (Decimal point drop down & Final sum)

    var stage = 1;
    if (progress >= 0.18 && progress < 0.38) stage = 2;
    else if (progress >= 0.38 && progress < 0.59) stage = 3;
    else if (progress >= 0.59 && progress < 0.80) stage = 4;
    else if (progress >= 0.80) stage = 5;

    // Helper to draw highlighted column backing
    function highlightCol(colX, width) {
      ctx.fillStyle = 'rgba(59, 130, 246, 0.15)';
      ctx.fillRect(colX - width / 2, H / 2 - 55, width, 105);
    }

    if (stage === 2) highlightCol(colHund, 22);
    if (stage === 3) highlightCol(colTenths, 22);
    if (stage === 4) highlightCol(colOnes, 22);

    ctx.font = 'bold 18px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    // Draw operator
    ctx.fillStyle = '#9CA3AF';
    ctx.fillText('+', W / 2 - 62, rowVal2);

    // Row 1: 4 . 7 5
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('4', colOnes, rowVal1);
    ctx.fillStyle = (stage === 1 || stage === 5) ? '#F59E0B' : '#F3F4F6';
    ctx.fillText('.', colDot, rowVal1);
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('7', colTenths, rowVal1);
    ctx.fillText('5', colHund, rowVal1);

    // Row 2: 1 . 8 0
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('1', colOnes, rowVal2);
    ctx.fillStyle = (stage === 1 || stage === 5) ? '#F59E0B' : '#F3F4F6';
    ctx.fillText('.', colDot, rowVal2);
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('8', colTenths, rowVal2);
    // Highlight padded zero in blue/green
    ctx.fillStyle = '#60A5FA';
    ctx.fillText('0', colHund, rowVal2);

    // Separator line
    ctx.beginPath();
    ctx.moveTo(W / 2 - 70, rowLine);
    ctx.lineTo(W / 2 + 50, rowLine);
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 2.5;
    ctx.stroke();

    // Carry digit
    if (stage >= 3) {
      ctx.fillStyle = '#F59E0B';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.fillText('1', colOnes, rowCarry);
    }

    // Sum results appearing step-by-step
    ctx.font = 'bold 18px -apple-system, sans-serif';
    if (stage >= 2) {
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('5', colHund, rowSum);
    }
    if (stage >= 3) {
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('5', colTenths, rowSum);
    }
    if (stage >= 5) {
      ctx.fillStyle = '#EF4444'; // Red dot
      ctx.fillText('.', colDot, rowSum);
    }
    if (stage >= 4) {
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('6', colOnes, rowSum);
    }

    // Bottom text instructions
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = '#9CA3AF';
    ctx.font = '12px -apple-system, sans-serif';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Lining Up Decimal Points', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Align points and pad 1.8 to 1.80', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#60A5FA';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Hundredths Column', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('5 + 0 = 5 hundredths', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#F59E0B';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Tenths Column (Carry)', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('7 + 8 = 15. Write 5, carry 1 whole', W / 2, H - 22);
    } else if (stage === 4) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Ones Column', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('4 + 1 + 1 (carry) = 6 ones', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981'; // Green
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Sum = 6.55', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Drop the decimal point straight down', W / 2, H - 22);
    }
  }
};
